import * as React from 'react';
import { createComponent } from '../create-component.js';
import Component from '../../components/accordion/src/accordion.component.js';
const tagName = 'made-accordion';
Component.define(tagName);
/**
 * @summary An accordion is a vertically stacked list of headers that reveal or hide associated sections of content.
 * @documentation '../../components/accordion/stories/accordion.mdx'
 *
 * @dependency made-accordion-item
 *
 * @fires mde-show - Emitted when an accordion item is expanded.
 * @fires mde-hide - Emitted when an accordion item is collapsed.
 *
 * @slot - One or more made-accordion-item elements.
 *
 * @csspart base - The component's base wrapper.
 */
const reactWrapper = createComponent({
    tagName,
    elementClass: Component,
    react: React,
    events: {
        onMdeShow: 'mde-show',
        onMdeHide: 'mde-hide'
    },
    displayName: 'MadeAccordion'
});
export default reactWrapper;
